INSERT INTO questions (id, specialty, category, domain_name, subtopic, difficulty, stem, choices, correct_answer, explanation, "references", status, telemetry) VALUES
('authored-batch-r3-016', 'Ophthalmic', 'Ophthalmic', 'Subspecialty Care', 'Oculocardiac reflex during strabismus surgery', 'easy', 'A 4-year-old, 16-kg child is undergoing bilateral medial rectus recession for strabismus under general anesthesia with sevoflurane and a laryngeal mask airway, breathing spontaneously. The case is maintained without an anticholinergic. As the surgeon places traction on the right medial rectus muscle, the heart rate abruptly falls from 110 to 48 beats/min with frequent premature ventricular complexes; blood pressure is 78/45 mmHg and SpO2 is 99%. What is the most appropriate IMMEDIATE next step?', '[{"text":"Ask the surgeon to release traction on the extraocular muscle","label":"A","correct":true,"rationale":"Correct: removing the triggering stimulus is the first-line maneuver and usually resolves the oculocardiac reflex within seconds before pharmacologic intervention is needed."},{"text":"Administer IV atropine 0.02 mg/kg immediately","label":"B","correct":false,"rationale":"Incorrect as the first action: an anticholinergic is given for persistent or recurrent bradycardia after the stimulus is removed, not before releasing traction."},{"text":"Give a 20 mL/kg crystalloid bolus to raise the heart rate","label":"C","correct":false,"rationale":"Incorrect: this bradycardia is vagally mediated from muscle traction, not hypovolemia, so fluid will not abolish the reflex."},{"text":"Deepen anesthesia with a propofol bolus","label":"D","correct":false,"rationale":"Incorrect: deepening anesthesia (especially with TIVA) does not blunt and may even increase oculocardiac reflex incidence, and would worsen the hypotension."},{"text":"Begin chest compressions and call for the code cart","label":"E","correct":false,"rationale":"Incorrect: the patient has a perfusing rhythm with adequate blood pressure and oxygenation, so compressions are not indicated."}]'::jsonb, 'A', 'The oculocardiac (trigeminovagal) reflex is triggered by traction on the extraocular muscles or pressure on the globe, with the trigeminal nerve as the afferent and the vagus as the efferent limb. Strabismus surgery and medial rectus traction in children are classic provocations. The reflex is fatigable, so the immediate step is to ask the surgeon to release the stimulus, which usually restores the rhythm within seconds; atropine or glycopyrrolate is reserved for persistent or recurrent bradycardia.', '[{"url":"https://www.openanesthesia.org/keywords/oculocardiac-reflex/","source":"Oculocardiac Reflex - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-017', 'Ophthalmic', 'Ophthalmic', 'Subspecialty Care', 'Nitrous oxide interaction with intraocular gas tamponade', 'hard', 'A 63-year-old woman returns to the operating room for an unrelated incarcerated hernia repair 5 days after pars plana vitrectomy with intravitreal sulfur hexafluoride (SF6) gas tamponade for a macular hole; she has been instructed to position face-down. The anesthesiologist assistant is planning a general anesthetic. Which intraoperative decision is MOST important to prevent catastrophic vision loss in the operated eye?', '[{"text":"Administer nitrous oxide but limit the concentration to 50%","label":"A","correct":false,"rationale":"Incorrect: even sub-anesthetic nitrous oxide concentrations cause clinically significant bubble expansion and intraocular pressure spikes; no concentration is considered safe with an intraocular gas bubble."},{"text":"Avoid nitrous oxide and maintain anesthesia with an air/oxygen and volatile or total intravenous technique","label":"B","correct":true,"rationale":"Correct: nitrous oxide diffuses into the SF6 bubble faster than nitrogen leaves, expanding the bubble, raising intraocular pressure, and threatening retinal perfusion, so it must be avoided until the gas resorbs."},{"text":"Avoid all volatile anesthetics because they raise intraocular pressure","label":"C","correct":false,"rationale":"Incorrect: volatile agents actually lower intraocular pressure and are acceptable; the agent that must be avoided is nitrous oxide."},{"text":"Keep the patient supine rather than face-down to reduce ocular pressure","label":"D","correct":false,"rationale":"Incorrect: positioning is dictated by the retinal surgeon and does not address the gas-expansion mechanism, which is driven by nitrous oxide diffusion."},{"text":"Limit peak airway pressures to below 20 cmH2O to protect the globe","label":"E","correct":false,"rationale":"Incorrect: airway pressure does not meaningfully affect an intravitreal gas bubble, whereas nitrous oxide exposure directly expands it."}]'::jsonb, 'B', 'An intravitreal SF6 bubble can persist for up to several weeks and C3F8 for up to two months. Because nitrous oxide is far more soluble in blood than the inert fluorinated gas, it enters the closed bubble faster than the gas diffuses out, causing rapid expansion, a dangerous rise in intraocular pressure, compromised retinal arterial perfusion, and potentially irreversible blindness. Nitrous oxide must be withheld in any patient with intraocular gas until the bubble has fully resorbed, and patients are typically issued a warning bracelet for this reason.', '[{"url":"https://www.openanesthesia.org/keywords/nitrous-oxide/","source":"Nitrous Oxide - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-018', 'Pediatric', 'Pediatric', 'Subspecialty Care', 'Fluid, electrolyte, and acid-base management (hypertrophic pyloric stenosis)', 'medium', 'A 5-week-old, 4.2 kg former full-term male presents for pyloromyotomy after a 10-day history of progressive nonbilious projectile vomiting. He appears lethargic with dry mucous membranes and sunken fontanelle. Laboratory studies show: sodium 134 mEq/L, potassium 2.9 mEq/L, chloride 88 mEq/L, bicarbonate 36 mEq/L, and pH 7.52. The surgeon asks to proceed to the operating room immediately. What is the most appropriate next step in management?', '[{"text":"Proceed immediately with a rapid sequence induction because the dehydration increases aspiration risk","label":"A","correct":false,"rationale":"Incorrect: although aspiration risk is real and a rapid sequence (or modified) induction with gastric suctioning is used, surgery should not proceed until the metabolic alkalosis and hypokalemia are corrected."},{"text":"Administer intravenous acetazolamide to correct the metabolic alkalosis before induction","label":"B","correct":false,"rationale":"Incorrect: the alkalosis is chloride-responsive and resolves with saline and potassium repletion, so a carbonic anhydrase inhibitor is unnecessary and may worsen volume and potassium status."},{"text":"Delay surgery to administer 0.9% sodium chloride with potassium supplementation and correct the electrolyte and acid-base derangements","label":"C","correct":true,"rationale":"Correct: pyloric stenosis is a medical, not a surgical, emergency, and the hypochloremic, hypokalemic metabolic alkalosis with dehydration must be corrected before anesthesia to avoid postoperative apnea and arrhythmia."},{"text":"Give a bolus of 0.45% sodium chloride in 5% dextrose to rapidly restore free water before surgery","label":"D","correct":false,"rationale":"Incorrect: hypotonic fluid is inappropriate for resuscitation here because chloride repletion with isotonic saline is required to reverse the alkalosis and the contraction of extracellular volume."},{"text":"Proceed with an inhalational induction using sevoflurane and spontaneous ventilation given the infant''s small size","label":"E","correct":false,"rationale":"Incorrect: a full or partially obstructed stomach mandates airway protection rather than spontaneous ventilation, and surgery should still be deferred until metabolic correction is achieved."}]'::jsonb, 'C', 'Hypertrophic pyloric stenosis produces a hypochloremic, hypokalemic metabolic alkalosis from loss of gastric hydrogen and chloride, with secondary hypovolemia. Because the unresolved alkalosis blunts central respiratory drive (via slow-equilibrating CSF pH) and hypokalemia predisposes to arrhythmia, the condition must be medically optimized before induction. Targets generally include serum chloride above 100 mEq/L, bicarbonate below 30 mEq/L, and adequate urine output before proceeding.', '[{"url":"https://www.openanesthesia.org/keywords/pyloric-stenosis/","source":"Pyloric Stenosis"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-019', 'Pediatric', 'Pediatric', 'Subspecialty Care', 'Airway emergencies (laryngospasm management)', 'easy', 'A previously healthy 3-year-old, 15 kg child undergoing adenotonsillectomy is extubated awake at the end of the case. Within seconds the child develops complete airway obstruction with paradoxical chest movement, tracheal tug, and no air movement despite a tight mask seal. SpO2 falls from 99% to 84%. Jaw thrust, removal of oral secretions, and 100% oxygen with continuous positive airway pressure fail to break the obstruction. An intravenous line is patent. Which of the following is the most appropriate next intervention?', '[{"text":"Deepen anesthesia with an additional dose of inhaled sevoflurane via the obstructed airway","label":"A","correct":false,"rationale":"Incorrect: with complete obstruction there is no gas exchange, so delivering volatile agent across the closed cords is ineffective and wastes critical time."},{"text":"Perform immediate needle cricothyroidotomy to establish a surgical airway","label":"B","correct":false,"rationale":"Incorrect: a front-of-neck airway is reserved for a true ''cannot intubate, cannot oxygenate'' situation after pharmacologic measures fail, not as the first response to laryngospasm with IV access available."},{"text":"Reintubate the trachea immediately without administering any medication","label":"C","correct":false,"rationale":"Incorrect: attempting to force a tube through tightly apposed cords is likely to fail and traumatize the larynx, whereas pharmacologic relaxation first makes intubation unnecessary or far easier."},{"text":"Administer intravenous succinylcholine to relax the laryngeal musculature","label":"D","correct":true,"rationale":"Correct: when positive-pressure maneuvers fail to break laryngospasm and desaturation is progressing, a small dose of intravenous succinylcholine rapidly relaxes the cords and is the definitive step."},{"text":"Administer intravenous atropine to reduce vagally mediated airway reactivity","label":"E","correct":false,"rationale":"Incorrect: atropine is useful to treat or prevent the bradycardia that may accompany hypoxia or succinylcholine, but it does not relieve the laryngospasm itself."}]'::jsonb, 'D', 'Laryngospasm is a sustained glottic closure reflex most common at extubation in children and after airway surgery. First-line management is removal of the stimulus, jaw thrust with firm pressure at the laryngospasm notch (Larson''s maneuver), and CPAP with 100% oxygen. When these fail and oxygen saturation is falling, intravenous succinylcholine (with atropine to prevent bradycardia) is the definitive treatment; if no IV is present, an intramuscular dose can be given.', '[{"url":"https://www.openanesthesia.org/keywords/laryngospasm/","source":"Laryngospasm"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-020', 'Pediatric', 'Pediatric', 'Subspecialty Care', 'Postoperative complications (emergence delirium)', 'medium', 'A 4-year-old, 17 kg child with no significant medical history undergoes bilateral myringotomy and tube placement under sevoflurane by mask. In the recovery area, shortly after awakening, the child is inconsolably thrashing, does not make eye contact, does not recognize the parents, and cannot be comforted. Vital signs are stable, SpO2 is 99% on room air, the surgical site is dry, and a focused exam reveals no signs of airway obstruction or bladder distention. A nurse asks how to manage the agitation. Which of the following is the most likely diagnosis and appropriate management?', '[{"text":"Postoperative pain; treat with an additional dose of intravenous opioid","label":"A","correct":false,"rationale":"Incorrect: myringotomy is minimally painful and the child shows non-purposeful agitation without recognition of caregivers, which is more consistent with emergence delirium than uncontrolled pain."},{"text":"Hypoxemia; treat with supplemental oxygen and airway repositioning","label":"B","correct":false,"rationale":"Incorrect: an SpO2 of 99% on room air with no obstruction excludes hypoxia as the cause of the agitation."},{"text":"Local anesthetic systemic toxicity; treat with intravenous lipid emulsion","label":"C","correct":false,"rationale":"Incorrect: no local anesthetic was administered for a mask sevoflurane myringotomy, so lipid rescue is not indicated."},{"text":"Full bladder causing distress; treat with bladder catheterization","label":"D","correct":false,"rationale":"Incorrect: bladder distention was specifically excluded on exam and is an uncommon cause after a brief myringotomy with minimal fluids."},{"text":"Emergence delirium; treat with a small dose of intravenous dexmedetomidine or propofol","label":"E","correct":true,"rationale":"Correct: the self-limited, non-purposeful agitation with lack of caregiver recognition after a sevoflurane anesthetic in a preschool-aged child is classic emergence delirium, which responds to dexmedetomidine, propofol, or an opioid such as fentanyl."}]'::jsonb, 'E', 'Emergence delirium is a transient state of disorientation, non-purposeful agitation, and inconsolability seen most often in children aged 2 to 6 years, particularly after sevoflurane or desflurane and short procedures with little intrinsic pain. It is a diagnosis of exclusion: hypoxia, pain, hypoglycemia, and bladder distention must be ruled out first. The condition is usually self-limited, but distressing or unsafe agitation is treated with dexmedetomidine, propofol, or fentanyl; intraoperative dexmedetomidine or propofol reduces its incidence.', '[{"url":"https://www.openanesthesia.org/keywords/emergence-delirium/","source":"Emergence Delirium in Children"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-021', 'Principles & Preop', 'Principles & Preop', 'Subspecialty Care', 'Preoperative cardiac risk stratification and functional capacity assessment', 'medium', 'A 68-year-old man is scheduled for an elective open right hemicolectomy for colon cancer. His history includes type 2 diabetes on insulin, hypertension, and a transient ischemic attack 3 years ago. He reports that he is able to walk on a flat surface and do light housework but becomes short of breath and has to stop after climbing one flight of stairs. His resting ECG shows nonspecific ST-T changes unchanged from a tracing 1 year ago, and he has no active cardiac symptoms. Vitals are stable. According to the ACC/AHA stepwise approach to perioperative cardiac evaluation, what is the most appropriate next step in his cardiac workup?', '[{"text":"Proceed to surgery without further cardiac testing","label":"A","correct":true,"rationale":"Correct: his procedure carries elevated risk and his functional capacity is poor/indeterminate, but current guidelines recommend proceeding when further testing would not change perioperative management."},{"text":"Obtain pharmacologic stress testing before surgery","label":"B","correct":false,"rationale":"Incorrect: stress testing is only indicated when it would change management, and there is no plan for revascularization purely to reduce noncardiac surgical risk here."},{"text":"Obtain a resting transthoracic echocardiogram to measure ejection fraction","label":"C","correct":false,"rationale":"Incorrect: routine preoperative echocardiography is not indicated in a patient without signs or symptoms of new or worsening heart failure or valvular disease."},{"text":"Refer for coronary angiography with possible preoperative revascularization","label":"D","correct":false,"rationale":"Incorrect: prophylactic coronary revascularization before noncardiac surgery does not improve outcomes and is reserved for patients who would need it independent of surgery."},{"text":"Cancel surgery and refer to cardiology for a 6-week optimization program","label":"E","correct":false,"rationale":"Incorrect: cancellation is unwarranted for an oncologic resection in a stable patient when no intervention would alter perioperative management."}]'::jsonb, 'A', 'In the ACC/AHA stepwise algorithm, after confirming the absence of an acute coronary syndrome and estimating combined surgical/clinical risk, the decision to test hinges on whether functional capacity is adequate AND whether testing would change management. Even though this patient has poor functional capacity (<4 METs) and an elevated Revised Cardiac Risk Index, additional noninvasive testing is recommended only if the result would alter perioperative care. Because neither revascularization nor cancellation is indicated for this stable patient, the correct step is to proceed to surgery with appropriate medical optimization and monitoring.', '[{"url":"https://www.openanesthesia.org/keywords/preoperative-cardiac-risk-stratification-and-evaluation/","source":"Preoperative Cardiac Risk Stratification and Evaluation - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-022', 'Principles & Preop', 'Principles & Preop', 'Subspecialty Care', 'Preoperative airway assessment and difficult airway prediction', 'medium', 'During a preoperative airway examination of a 52-year-old woman scheduled for thyroidectomy, you ask her to sit upright, open her mouth maximally, and protrude her tongue without phonating. You can see the soft palate and the base of the uvula, but the uvular tip and the tonsillar pillars are obscured by the tongue. She has a thyromegaly, a thyromental distance of 5 cm, and full neck extension. Which modified Mallampati class best describes this airway view, and what is its general significance?', '[{"text":"Class I — full view of the soft palate, uvula, and tonsillar pillars; reassuring for easy laryngoscopy","label":"A","correct":false,"rationale":"Incorrect: Class I requires visualization of the entire uvula and pillars, which are obscured in this patient."},{"text":"Class III — only the soft palate and the base of the uvula are visible; associated with increased likelihood of difficult laryngoscopy","label":"B","correct":true,"rationale":"Correct: visualization limited to the soft palate and uvular base defines class III, which correlates with a higher rate of difficult intubation."},{"text":"Class II — soft palate and uvula visible but pillars obscured; generally favorable","label":"C","correct":false,"rationale":"Incorrect: Class II still permits visualization of the uvula in its entirety, whereas here only the uvular base is seen."},{"text":"Class IV — only the hard palate is visible; predicts the most difficult view","label":"D","correct":false,"rationale":"Incorrect: class IV is reserved for cases in which the soft palate cannot be seen at all and only the hard palate is visible."},{"text":"Class 0 — the epiglottis is visible; an extremely favorable view","label":"E","correct":false,"rationale":"Incorrect: class 0 requires direct visualization of the epiglottis, which is not described here."}]'::jsonb, 'B', 'The modified Mallampati classification is performed with the patient seated, mouth maximally open, tongue protruded, and without phonation. Class I shows the soft palate, fauces, uvula, and pillars; class II shows the soft palate, fauces, and uvula; class III shows only the soft palate and the base of the uvula; and class IV shows only the hard palate. Higher classes (III and IV) are associated with an increased risk of difficult laryngoscopy, though the test has modest sensitivity and should be combined with other predictors such as thyromental distance and neck mobility.', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK585119/","source":"Mallampati Score - StatPearls - NCBI Bookshelf"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-023', 'Neuro', 'Neuro', 'Subspecialty Care', 'Cerebral autoregulation and CPP management in traumatic brain injury', 'medium', 'A 58-year-old man with longstanding poorly controlled hypertension (home BP often 170/100 mmHg) sustains a severe traumatic brain injury in a motor vehicle collision. An intraventricular catheter reads an intracranial pressure (ICP) of 22 mmHg. On arrival his blood pressure is 150/90 mmHg (MAP 110 mmHg). The neurosurgical team asks you to target a cerebral perfusion pressure (CPP) of 60-70 mmHg per Brain Trauma Foundation guidance while you manage his anesthetic for ICP control. Compared with a previously normotensive patient, which feature of this patient''s cerebral autoregulation most directly increases his risk of cerebral ischemia if his MAP is allowed to fall toward 65 mmHg?', '[{"text":"Chronic hypertension shifts the autoregulatory curve to the left, lowering the threshold at which cerebral blood flow becomes pressure-passive","label":"A","correct":false,"rationale":"Incorrect: chronic hypertension shifts the curve to the right, not left; a leftward shift would make him more tolerant of low MAP, the opposite of the actual risk."},{"text":"Chronic hypertension abolishes autoregulation entirely so cerebral blood flow is linearly pressure-dependent across all MAP values","label":"B","correct":false,"rationale":"Incorrect: autoregulation is preserved but its operating range is shifted, not abolished, in chronic hypertension."},{"text":"Chronic hypertension shifts the autoregulatory curve to the right, raising the lower limit of autoregulation so ischemia occurs at a higher MAP","label":"C","correct":true,"rationale":"Correct: sustained hypertension shifts the entire autoregulation curve rightward, elevating the lower autoregulatory threshold so that a MAP tolerated by a normotensive patient may already be below this patient''s ischemic limit."},{"text":"Chronic hypertension widens the autoregulatory plateau, broadening the MAP range over which cerebral blood flow stays constant","label":"D","correct":false,"rationale":"Incorrect: chronic hypertension does not widen the plateau; if anything the curve shifts rightward and the safe range relative to baseline narrows."},{"text":"Chronic hypertension lowers the upper limit of autoregulation, making hyperemia the dominant risk at a MAP of 65 mmHg","label":"E","correct":false,"rationale":"Incorrect: the upper limit shifts upward (rightward) in chronic hypertension, and a MAP of 65 mmHg poses an ischemic—not hyperemic—threat."}]'::jsonb, 'C', 'Cerebral autoregulation maintains roughly constant cerebral blood flow across a MAP of about 60-160 mmHg (CPP ~50-150 mmHg) in healthy adults. Chronic hypertension shifts this curve to the right, raising both the lower and upper limits, so a chronically hypertensive patient becomes ischemic at a MAP that a normotensive patient would tolerate. This is why guidelines caution against aggressively lowering MAP and recommend keeping pressure within roughly 20-25% of baseline; in TBI, driving CPP to the low end of a generic target may fall below this patient''s shifted lower autoregulatory limit.', '[{"url":"https://www.openanesthesia.org/keywords/cerebral-autoregulation/","source":"Cerebral Autoregulation - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-024', 'Neuro', 'Neuro', 'Subspecialty Care', 'Venous air embolism in sitting-position posterior fossa surgery', 'medium', 'A 44-year-old woman undergoes resection of a posterior fossa meningioma in the sitting position under general anesthesia. About 90 minutes into the case, while the surgeon is working near a venous sinus, the end-tidal CO2 abruptly falls from 35 to 19 mmHg, the precordial Doppler emits a sudden harsh ''mill-wheel'' churning sound, and the blood pressure drops to 78/44 mmHg. A right atrial catheter is in place. After asking the surgeon to flood the field with saline and applying jugular venous compression, which intervention is the most appropriate immediate next step?', '[{"text":"Place the patient in steep reverse Trendelenburg to lower venous pressure at the surgical site","label":"A","correct":false,"rationale":"Incorrect: reverse Trendelenburg would worsen the situation by further lowering pressure at the wound, promoting continued air entrainment."},{"text":"Increase the tidal volume and add 10 cmH2O of PEEP to raise mean airway pressure and tamponade the venous opening","label":"B","correct":false,"rationale":"Incorrect: high PEEP is unreliable for stopping entrainment and can promote paradoxical air embolism via a patent foramen ovale by raising right atrial pressure."},{"text":"Administer a 500 mL crystalloid bolus and start a phenylephrine infusion before any other maneuver","label":"C","correct":false,"rationale":"Incorrect: although hemodynamic support is appropriate, it is adjunctive and should not precede stopping nitrous oxide, giving 100% oxygen, and aspirating the catheter."},{"text":"Discontinue nitrous oxide if in use, deliver 100% oxygen, and aspirate air from the right atrial catheter","label":"D","correct":true,"rationale":"Correct: stopping nitrous oxide prevents expansion of entrained air, 100% oxygen supports oxygenation and aids nitrogen washout from the bubble, and aspirating the right atrial catheter directly removes air from the heart."},{"text":"Hyperventilate the patient to an end-tidal CO2 of 25 mmHg to reduce cerebral blood volume and brain bulk","label":"E","correct":false,"rationale":"Incorrect: hyperventilation does not treat venous air embolism and the low end-tidal CO2 here reflects dead-space from the embolism, not a target to chase."}]'::jsonb, 'D', 'Venous air embolism is a major hazard of sitting-position posterior fossa surgery, where the wound lies above the heart and open venous channels entrain air. The classic signs are a sudden drop in end-tidal CO2 (increased dead space), a mill-wheel murmur or Doppler change, and hypotension. Management is to notify the surgeon to occlude the source (flood the field, wax bone edges, jugular compression), discontinue nitrous oxide and give 100% oxygen to prevent bubble expansion and aid resorption, aspirate air through a right atrial catheter, and support hemodynamics. Nitrous oxide is contraindicated once VAE is suspected because it rapidly enlarges the air bubble.', '[{"url":"https://www.openanesthesia.org/keywords/venous-air-embolism/","source":"Venous Air Embolism - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-025', 'Neuro', 'Neuro', 'Subspecialty Care', 'Anesthetic effects on intraoperative motor evoked potential monitoring', 'medium', 'A 16-year-old girl is undergoing posterior spinal instrumentation and fusion for adolescent idiopathic scoliosis. Intraoperative neuromonitoring includes both somatosensory evoked potentials (SSEPs) and transcranial motor evoked potentials (MEPs). The neurophysiologist tells you that the MEP signals have become difficult to obtain and asks you to optimize the anesthetic so that reliable MEP recordings are possible during the correction maneuver. Which anesthetic management change is most likely to improve the quality of the transcranial MEP recordings?', '[{"text":"Maintain a continuous nondepolarizing neuromuscular blockade titrated to a train-of-four of two twitches","label":"A","correct":false,"rationale":"Incorrect: neuromuscular blockade attenuates the compound muscle action potential that MEPs depend on, degrading rather than improving motor recordings."},{"text":"Increase the inhaled sevoflurane concentration to 1.5 MAC to deepen anesthesia and reduce movement","label":"B","correct":false,"rationale":"Incorrect: halogenated volatile agents depress MEP amplitude in a dose-dependent fashion (affecting MEPs more than SSEPs), so increasing sevoflurane worsens the signal."},{"text":"Add a high-dose bolus of dexmedetomidine to provide background sedation and reduce volatile requirements","label":"C","correct":false,"rationale":"Incorrect: while low-dose dexmedetomidine may be an adjunct, high-dose boluses can depress MEP amplitude and are not the primary fix for poor signals."},{"text":"Deepen the anesthetic with a bolus of nitrous oxide added to the volatile carrier gas","label":"D","correct":false,"rationale":"Incorrect: nitrous oxide depresses evoked potential amplitudes, particularly MEPs, and adding it would further degrade the recordings."},{"text":"Transition to a total intravenous anesthetic with propofol and an opioid infusion while minimizing volatile agent","label":"E","correct":true,"rationale":"Correct: propofol-based TIVA with an opioid suppresses MEPs far less than volatile agents, making it the preferred technique for reliable motor monitoring."}]'::jsonb, 'E', 'Transcranial motor evoked potentials are highly sensitive to anesthetic depression, and halogenated volatile agents and nitrous oxide reduce MEP amplitude in a dose-dependent manner—more so than they affect SSEPs. A propofol-based total intravenous anesthetic with an opioid is therefore the standard technique when reliable MEP monitoring is required, as in scoliosis correction. Because MEPs are recorded as compound muscle action potentials, neuromuscular blockade must be avoided or kept minimal; deep blockade abolishes the motor response even though SSEPs are unaffected.', '[{"url":"https://www.openanesthesia.org/keywords/evoked-potentials-modalities-and-anesthetic-effects/","source":"Evoked Potentials: Modalities and Anesthetic Effects - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-026', 'Obstetric', 'Obstetric', 'Subspecialty Care', 'Hypertensive disorders of pregnancy — magnesium sulfate toxicity', 'medium', 'A 33-year-old G1 woman at 35 weeks with preeclampsia with severe features is receiving an intravenous magnesium sulfate infusion for seizure prophylaxis. Her blood pressure is controlled at 148/94 mmHg. Over the past 30 minutes she has become increasingly drowsy and reports flushing and weakness. On examination her patellar deep tendon reflexes are absent, respiratory rate is 10/min, and oxygen saturation is 93% on room air. Urine output has fallen to 10 mL/hr. What is the most appropriate immediate intervention?', '[{"text":"Stop the magnesium infusion and administer intravenous calcium gluconate","label":"A","correct":true,"rationale":"Stopping the magnesium and giving IV calcium (the direct physiologic antagonist) is the correct management of acute magnesium toxicity with respiratory depression and areflexia."},{"text":"Increase the magnesium sulfate infusion rate to better control her neurologic symptoms","label":"B","correct":false,"rationale":"Her drowsiness, areflexia, and respiratory depression are signs of magnesium toxicity, so increasing the dose would deepen the toxicity and risk respiratory and cardiac arrest."},{"text":"Administer a benzodiazepine for presumed impending eclamptic seizure","label":"C","correct":false,"rationale":"Her depressed sensorium reflects magnesium toxicity rather than seizure activity, and a benzodiazepine would further depress respiration."},{"text":"Administer furosemide to increase urine output and accelerate magnesium clearance","label":"D","correct":false,"rationale":"Diuresis is too slow to reverse acute respiratory depression and risks worsening hypovolemia, so it does not address the immediate threat."},{"text":"Administer naloxone to reverse the respiratory depression","label":"E","correct":false,"rationale":"Naloxone reverses opioid-induced respiratory depression but has no effect on magnesium-induced neuromuscular and respiratory depression."}]'::jsonb, 'A', 'Loss of deep tendon reflexes is the earliest reliable clinical sign of magnesium toxicity (typically around 8-10 mg/dL), followed by respiratory depression (~12 mg/dL) and ultimately cardiac arrest at higher levels. Oliguria from preeclampsia reduces renal magnesium clearance and predisposes to accumulation. Immediate management is to stop the infusion and give IV calcium gluconate (1 g) or calcium chloride, which directly antagonizes magnesium at the neuromuscular junction, while supporting ventilation. Reflexes should be monitored at the bedside during any magnesium infusion.', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK430839/","source":"Hypertension In Pregnancy — StatPearls (NCBI Bookshelf)"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-027', 'Obstetric', 'Obstetric', 'Subspecialty Care', 'Obstetric hemorrhage — uterotonic selection in uterine atony', 'medium', 'A 38-year-old G4P3 woman with chronic hypertension delivers a 4,300 g infant after a prolonged second stage. Her current blood pressure is 168/102 mmHg. Within minutes of delivery she has brisk vaginal bleeding; the uterus is boggy and palpable above the umbilicus. Oxytocin is already infusing at a high rate and fundal massage has been started, but bleeding continues and the uterus remains atonic. Which second-line uterotonic is most appropriate to administer next?', '[{"text":"Methylergonovine 200 mcg intramuscularly","label":"A","correct":false,"rationale":"Methylergonovine is contraindicated in this hypertensive patient because its alpha-adrenergic vasoconstriction can precipitate a severe, sometimes fatal, hypertensive crisis or stroke."},{"text":"Carboprost (15-methyl PGF2-alpha) 250 mcg intramuscularly","label":"B","correct":true,"rationale":"Carboprost effectively treats atony and is the preferred second-line agent here because the contraindicated alternative is the ergot, though it should be used cautiously given any reactive airway disease."},{"text":"A repeat intravenous bolus of oxytocin 40 units given as rapid push","label":"C","correct":false,"rationale":"Rapid undiluted oxytocin boluses cause vasodilation, hypotension, and tachycardia, and simply escalating an agent that has already failed does not add a new mechanism."},{"text":"Intravenous magnesium sulfate to relax the uterus and reduce blood pressure","label":"D","correct":false,"rationale":"Magnesium is a tocolytic that relaxes uterine smooth muscle and would worsen atony and bleeding, the opposite of what is needed."},{"text":"Terbutaline 250 mcg subcutaneously","label":"E","correct":false,"rationale":"Terbutaline is a beta-agonist tocolytic that further relaxes the uterus, aggravating atony and hemorrhage."}]'::jsonb, 'B', 'This is uterine atony, the leading cause of primary postpartum hemorrhage, with classic risk factors of grand multiparity, macrosomia, and prolonged labor. When oxytocin and massage fail, a second-line uterotonic with a different mechanism is indicated. Methylergonovine (an ergot alkaloid) is contraindicated in hypertension and preeclampsia because of its vasoconstrictive effect, so carboprost is the appropriate choice here — with the caveat that prostaglandin F2-alpha analogues can cause bronchospasm and should be avoided in significant asthma. Misoprostol is another option when both ergots and prostaglandin injectables are contraindicated.', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK499988/","source":"Postpartum Hemorrhage — StatPearls (NCBI Bookshelf)"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-028', 'Ambulatory', 'Ambulatory', 'Subspecialty Care', 'Patient selection and facility appropriateness (obstructive sleep apnea)', 'medium', 'A 54-year-old man with a BMI of 41 kg/m2, hypertension, and type 2 diabetes is scheduled for an elective unilateral inguinal hernia repair at a freestanding ambulatory surgery center. He reports loud snoring, witnessed apneas, and daytime somnolence; his STOP-Bang score is 6. He has never had a formal sleep study and is not on CPAP. His blood pressure is 148/88 mmHg and SpO2 is 96% on room air. The surgeon plans general anesthesia with an LMA and expects to use intraoperative and postoperative opioids for analgesia. Which factor most strongly supports rescheduling this case at a facility with extended postoperative monitoring rather than proceeding at the freestanding center?', '[{"text":"His BMI of 41 kg/m2 alone, which is an absolute contraindication to ambulatory surgery","label":"A","correct":false,"rationale":"Incorrect, because obesity by itself is not an absolute contraindication to ambulatory surgery; appropriately selected patients with high BMI can undergo outpatient procedures when comorbidities are optimized."},{"text":"His blood pressure of 148/88 mmHg, which mandates inpatient management","label":"B","correct":false,"rationale":"Incorrect, because stage 1 hypertension without evidence of end-organ ischemia does not require inpatient management and is not a reason to cancel or transfer an ambulatory case."},{"text":"The combination of a high STOP-Bang score (presumed severe OSA) with an anesthetic plan requiring substantial postoperative opioids","label":"C","correct":true,"rationale":"Correct, because presumed-severe untreated OSA combined with an opioid-dependent analgesic plan markedly raises the risk of postoperative respiratory depression and airway obstruction, which exceeds what a freestanding center can safely monitor."},{"text":"The planned use of an LMA, which is unsafe in patients with obstructive sleep apnea","label":"D","correct":false,"rationale":"Incorrect, because a supraglottic airway is not contraindicated in OSA and the airway device choice is not the principal driver of postoperative disposition risk."},{"text":"His type 2 diabetes, which precludes same-day discharge after general anesthesia","label":"E","correct":false,"rationale":"Incorrect, because well-controlled diabetes is routinely managed in the ambulatory setting and does not by itself preclude same-day discharge."}]'::jsonb, 'C', 'Patient selection for the freestanding ambulatory setting hinges on matching procedural and anesthetic risk to the facility''s monitoring capability. A patient with presumed severe, untreated OSA (STOP-Bang 6) who will require significant postoperative opioids faces a meaningfully elevated risk of opioid-induced respiratory depression and airway obstruction; the SAMBA/ASA guidance favors an opioid-sparing, multimodal plan and a facility capable of extended monitoring when severe OSA cannot be mitigated. Isolated factors such as obesity, controlled hypertension, or diabetes are not independent disqualifiers.', '[{"url":"https://www.openanesthesia.org/keywords/obstructive-sleep-apnea/","source":"Obstructive Sleep Apnea: Pathophysiology (OpenAnesthesia)"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-029', 'Ambulatory', 'Ambulatory', 'Subspecialty Care', 'Postoperative nausea and vomiting prophylaxis and risk stratification', 'medium', 'A healthy 24-year-old nonsmoking woman is scheduled for an outpatient laparoscopic cholecystectomy under general anesthesia. She reports severe nausea and vomiting after a prior tonsillectomy and a history of motion sickness. The planned anesthetic includes volatile agent maintenance and intraoperative opioids. Recognizing she has four Apfel risk factors, the anesthesia team wants to minimize her postoperative nausea and vomiting (PONV) risk to avoid an unplanned admission. Which intervention is the most effective single modification to reduce her baseline PONV risk?', '[{"text":"Administering a single prophylactic dose of ondansetron at the end of surgery as the only intervention","label":"A","correct":false,"rationale":"Incorrect, because a single antiemetic provides only modest relative risk reduction and is inadequate as sole prophylaxis in a patient with four risk factors."},{"text":"Adding nitrous oxide to reduce the required volatile concentration","label":"B","correct":false,"rationale":"Incorrect, because nitrous oxide is itself an independent emetogenic agent and would increase rather than decrease PONV risk."},{"text":"Withholding all antiemetic prophylaxis and treating nausea only if it occurs in recovery","label":"C","correct":false,"rationale":"Incorrect, because a rescue-only strategy is inappropriate for a high-risk patient and ignores the value of reducing baseline risk and combining prophylactic agents."},{"text":"Replacing volatile-based maintenance with propofol total intravenous anesthesia (TIVA) and minimizing opioids","label":"D","correct":true,"rationale":"Correct, because substituting a propofol-based TIVA for volatile maintenance and reducing opioids directly removes two major anesthetic triggers, lowering the patient''s baseline risk before pharmacologic prophylaxis is added."},{"text":"Giving generous intraoperative opioids to ensure deep analgesia and prevent pain-related nausea","label":"E","correct":false,"rationale":"Incorrect, because opioids are a dose-dependent cause of PONV, so liberal opioid use raises rather than lowers her risk."}]'::jsonb, 'D', 'In a patient with four Apfel risk factors, the most impactful step is to lower baseline risk by modifying the anesthetic itself rather than relying on a single antiemetic. Switching from volatile maintenance to propofol TIVA and minimizing opioids each independently reduce PONV, and these baseline reductions are then layered with multimodal pharmacologic prophylaxis using agents from different receptor classes. Nitrous oxide and liberal opioids both worsen PONV and should be avoided in this setting.', '[{"url":"https://www.openanesthesia.org/keywords/postoperative-nausea-and-vomiting/","source":"Postoperative Nausea and Vomiting in Adults (OpenAnesthesia)"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-030', 'Ambulatory', 'Ambulatory', 'Subspecialty Care', 'Perioperative emergencies in the ambulatory setting (malignant hyperthermia)', 'hard', 'During an elective outpatient knee arthroscopy under general anesthesia with sevoflurane and a single dose of succinylcholine for intubation at a freestanding surgery center, a 19-year-old man develops an unexplained rise in end-tidal CO2 to 68 mmHg despite increased minute ventilation, masseter rigidity, tachycardia to 140 bpm, and a temperature rising from 36.8 to 39.1 C over 20 minutes. Malignant hyperthermia is suspected. After calling for help and discontinuing the triggering agents, what is the single most important next pharmacologic intervention?', '[{"text":"Administer a beta-blocker to control the tachycardia","label":"A","correct":false,"rationale":"Incorrect, because the tachycardia reflects the underlying hypermetabolic crisis, and beta-blockade neither treats the cause nor addresses the life-threatening hyperthermia and acidosis."},{"text":"Give intravenous sodium bicarbonate as the primary treatment for the crisis","label":"B","correct":false,"rationale":"Incorrect, because while bicarbonate may be used to help correct metabolic acidosis, it is an adjunct and does not reverse the underlying ryanodine-receptor calcium dysregulation."},{"text":"Administer a calcium channel blocker such as verapamil to lower intracellular calcium","label":"C","correct":false,"rationale":"Incorrect, because calcium channel blockers do not treat MH and can cause dangerous hyperkalemia and cardiovascular collapse when combined with dantrolene."},{"text":"Deepen anesthesia with additional sevoflurane to control the sympathetic response","label":"D","correct":false,"rationale":"Incorrect, because sevoflurane is itself an MH trigger and continuing it would worsen the crisis rather than control it."},{"text":"Administer intravenous dantrolene 2.5 mg/kg immediately and repeat as needed","label":"E","correct":true,"rationale":"Correct, because dantrolene is the only definitive treatment for an MH crisis and must be given without delay at an initial dose of 2.5 mg/kg, titrated until the hypermetabolic signs resolve."}]'::jsonb, 'E', 'Malignant hyperthermia is a pharmacogenetic hypermetabolic crisis triggered by volatile agents and succinylcholine; the earliest and most sensitive sign is an unexplained rise in end-tidal CO2, often with masseter rigidity after succinylcholine. After stopping triggers, calling for help, and hyperventilating with 100% oxygen, dantrolene 2.5 mg/kg IV is the definitive treatment and must be given immediately and repeated until the hypermetabolic state resolves. Because MH can occur in any setting that uses triggering agents, every ambulatory facility administering volatile anesthetics or succinylcholine must stock a full supply of dantrolene and a transfer plan.', '[{"url":"https://www.openanesthesia.org/keywords/malignant-hyperthermia/","source":"Malignant Hyperthermia (OpenAnesthesia)"}]'::jsonb, 'sme_review', '{}'::jsonb);
